#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3+5;
int gra[MAXN][MAXN];
bool used[MAXN*3];
void output()
{
	FOR(i,1,4)
	{
		printf("%lld",gra[i][1]);
		FOR(j,2,4)
		{
			printf(" %lld",gra[i][j]);
		}
		printf("\n");
	}
	printf("\n");
}
void dfs(int x,int y)
{
	if(x>4){
		output();
		return;
	}
	if(gra[x][y]==1)
	{
		if(x==2&&y==2)
		{
			if(gra[1][1]+gra[1][2]+gra[2][1]+gra[2][2]!=34)
			{
				return;
			}
		}
		if(x==2&&y==4)
		{
			if(gra[1][3]+gra[1][4]+gra[2][3]+gra[2][4]!=34)
			{
				return;
			}
		}
		if(x==4&&y==2)
		{
			if(gra[3][1]+gra[3][2]+gra[4][1]+gra[4][2]!=34)
			{
				return;
			}
		}
		if(x==4&&y==4)
		{
			if(gra[3][3]+gra[3][4]+gra[4][3]+gra[4][4]!=34)
			{
				return;
			}
			if(gra[1][1]+gra[2][2]+gra[3][3]+gra[4][4]!=34)
			{
				return;
			}
			if(gra[1][1]+gra[1][4]+gra[4][1]+gra[4][4]!=34)
			{
				return;
			}
		}
		if(x==4&&y==1)
		{
			if(gra[1][4]+gra[4][1]+gra[2][3]+gra[3][2]!=34)
			{
				return;
			}
		}
		if(x==3&&y==3)
		{
			if(gra[2][2]+gra[2][3]+gra[3][2]+gra[3][3]!=34)
			{
				return;
			}
		}
		if(x==4){
			if(gra[1][y]+gra[2][y]+gra[3][y]+gra[4][y]!=34)
			{
				return;
			}
		}
		if(y==4)
		{
			if(gra[x][1]+gra[x][2]+gra[x][3]+gra[x][4]!=34)
			{
				return;
			}
		}
		if(y==4)dfs(x+1,1);
		else dfs(x,y+1);
	}
	else
	{
		FOR(i,2,16)
		{
			if(!used[i]){
				gra[x][y]=i;
				if(x==2&&y==2)
				{
					if(gra[1][1]+gra[1][2]+gra[2][1]+gra[2][2]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				if(x==2&&y==4)
				{
					if(gra[1][3]+gra[1][4]+gra[2][3]+gra[2][4]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				if(x==4&&y==2)
				{
					if(gra[3][1]+gra[3][2]+gra[4][1]+gra[4][2]!=34)
					{
						continue;
						gra[x][y]=0;
					}
				}
				if(x==4&&y==4)
				{
					if(gra[3][3]+gra[3][4]+gra[4][3]+gra[4][4]!=34)
					{
						gra[x][y]=0;
						continue;
					}
					if(gra[1][1]+gra[2][2]+gra[3][3]+gra[4][4]!=34)
					{
						gra[x][y]=0;
						continue;
					}
					if(gra[1][1]+gra[1][4]+gra[4][1]+gra[4][4]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				if(x==4&&y==1)
				{
					if(gra[1][4]+gra[4][1]+gra[2][3]+gra[3][2]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				if(x==3&&y==3)
				{
					if(gra[2][2]+gra[2][3]+gra[3][2]+gra[3][3]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				if(x==4)
				{
					if(gra[1][y]+gra[2][y]+gra[3][y]+gra[4][y]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				if(y==4)
				{
					if(gra[x][1]+gra[x][2]+gra[x][3]+gra[x][4]!=34)
					{
						gra[x][y]=0;
						continue;
					}
				}
				used[i]=true;
				if(y==4)dfs(x+1,1);
				else dfs(x,y+1);
				used[i]=false;
				gra[x][y]=0;
			}
		}
	}
}
signed main(void)
{
	int x,y;
	scanf("%lld%lld",&x,&y);
	cl(gra);
	cl(used);
	gra[x][y]=1;
	used[1]=true;
	dfs(1,1);
	return false;
}
